#include <iostream>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    long long n;
    cin >> n;

    // sum_{k=1..n} k*(k+1) = sum k^2 + sum k
    // sum k = n*(n+1)/2
    // sum k^2 = n*(n+1)*(2n+1)/6
    // So total = n*(n+1)*(2n+1)/6 + n*(n+1)/2
    // = n*(n+1)/2 * ((2n+1)/3 + 1)
    // = n*(n+1)*(n+2)/3
    //
    // We'll compute directly with 64-bit arithmetic.
    long long ans = n * (n + 1) / 2 * (2 * n + 1) / 3 + n * (n + 1) / 2;
    // Simpler closed form: n * (n + 1) * (n + 2) / 3
    // But careful with overflow: we can do:
    // ans = n * (n + 1) / 2 * (2 * n + 1) / 3 + n * (n + 1) / 2;
    // or simply:
    // ans = n * (n + 1) / 2 * (2 * n + 1) / 3 + n * (n + 1) / 2;
    // Let's verify with the direct formula:
    // Actually compute the simpler closed form n*(n+1)*(n+2)/3
    // Using the fact that n*(n+1)*(n+2) is always divisible by 3 for integer n.
    // But n can be up to 1e9, so n*(n+1)*(n+2) fits in 128-bit? 1e9*1e9*1e9 = 1e27 > 2^63-1 ~ 9.22e18.
    // So we need to be careful. Use the sum-of-squares approach.
    // n*(n+1)/2 is at most ~5e17, multiplied by (2n+1) ~ 2e9 gives ~1e27 - too big.
    // We'll use the closed form n*(n+1)*(n+2)/3 but with careful ordering.
    // Actually let's use 128-bit via __int128 if available, but for portability:
    // Let's compute using the sum-of-squares approach with modular-arithmetic-like ordering
    // or use the fact that n*(n+1)/2 is integer and (2n+1)/3 might not be integer.
    // Better: use the formula n*(n+1)*(n+2)/3 but compute as:
    // Since one of n, n+1, n+2 is divisible by 3, we can divide first.

    // Let's compute with unsigned long long and careful division.
    // n, n+1, n+2 consecutive => one divisible by 3.
    // Use unsigned long long to be safe.
    unsigned long long un = n;
    unsigned long long a = un;
    unsigned long long b = un + 1;
    unsigned long long c = un + 2;

    // Divide by 3 first
    if (a % 3 == 0) a /= 3;
    else if (b % 3 == 0) b /= 3;
    else c /= 3;

    unsigned long long ans2 = a * b * c;
    cout << ans2 << '\n';

    return 0;
}
